svg.script:
(function() {
  var svg = document.getElementById('root');
  var tip      = document.getElementById('tip');
  var tipPath  = document.getElementById('tip-path');
  var tipBdr   = document.getElementById('tip-bdr');
  var tipLine1 = document.getElementById('tip-line1');
  var tipLine2 = document.getElementById('tip-line2');
  var tipLine3 = document.getElementById('tip-line3');
  var W = 110, H = 54, TH = 10;

  function bubPath(x, y, flip) {
    var lx = x - W/2, rx = x + W/2, ty, by;
    if (!flip) {
      ty = y - TH - H; by = y - TH;
      return ['M',x-8,',',by,' L',lx+10,',',by,' Q',lx,',',by,' ',lx,',',by-10,
              ' L',lx,',',ty+10,' Q',lx,',',ty,' ',lx+10,',',ty,
              ' L',rx-10,',',ty,' Q',rx,',',ty,' ',rx,',',ty+10,
              ' L',rx,',',by-10,' Q',rx,',',by,' ',rx-10,',',by,
              ' L',x+8,',',by,' L',x,',',y,' Z'].join('');
    } else {
      ty = y + TH; by = y + TH + H;
      return ['M',x-8,',',ty,' L',lx+10,',',ty,' Q',lx,',',ty,' ',lx,',',ty+10,
              ' L',lx,',',by-10,' Q',lx,',',by,' ',lx+10,',',by,
              ' L',rx-10,',',by,' Q',rx,',',by,' ',rx,',',by-10,
              ' L',rx,',',ty+10,' Q',rx,',',ty,' ',rx-10,',',ty,
              ' L',x+8,',',ty,' L',x,',',y,' Z'].join('');
    }
  }

  function showTip(evt, name, val, pct) {
    var pt = svg.createSVGPoint();
    pt.x = evt.clientX; pt.y = evt.clientY;
    var sp = pt.matrixTransform(svg.getScreenCTM().inverse());
    var tx = Math.max(W/2+4, Math.min(sp.x, 1100-W/2-4));
    var ty = sp.y;
    var flip = ty < H + TH + 30;
    var p = bubPath(tx, ty, flip);
    tipPath.setAttribute('d', p); tipBdr.setAttribute('d', p);
    var textY = flip ? ty + TH + 16 : ty - TH - H + 16;
    var parts = name.split(' · ');
    tipLine1.setAttribute('x', tx); tipLine1.setAttribute('y', textY);
    tipLine1.setAttribute('text-anchor','middle');
    tipLine1.textContent = parts[0] + ' — ' + (parts[1]||'');
    tipLine2.setAttribute('x', tx); tipLine2.setAttribute('y', textY + 18);
    tipLine2.setAttribute('text-anchor','middle');
    tipLine2.textContent = 'Value: ' + val;
    tipLine3.setAttribute('x', tx); tipLine3.setAttribute('y', textY + 34);
    tipLine3.setAttribute('text-anchor','middle');
    tipLine3.textContent = 'Share within product: ' + pct;
    tip.style.opacity = '1';
  }

  var cells = svg.querySelectorAll('.mcell');
  cells.forEach(function(g) {
    var name = g.getAttribute('data-name');
    var val  = g.getAttribute('data-val');
    var pct  = g.getAttribute('data-pct');
    g.addEventListener('mouseenter', function(e){ showTip(e,name,val,pct); });
    g.addEventListener('mousemove',  function(e){ showTip(e,name,val,pct); });
    g.addEventListener('mouseleave', function(){ tip.style.opacity='0'; });
  });

  /* ── Dark / print toggles ── */
  var lightColors = {
    'USA':     '#00D4E8',
    'China':   '#00B87A',
    'UK':      '#F59E0B',
    'Germany': '#F43F5E',
    'France':  '#8B5CF6',
    'India':   '#3B82F6'
  };
  var darkColors = {
    'USA':     '#22D3EE',
    'China':   '#10B981',
    'UK':      '#FBB724',
    'Germany': '#FB6181',
    'France':  '#A78BFA',
    'India':   '#60A5FA'
  };

  function swapCellColors(dark) {
    var palette = dark ? darkColors : lightColors;
    svg.querySelectorAll('.mcell').forEach(function(g) {
      var name = g.getAttribute('data-name') || '';
      var country = name.split(' · ')[0];
      var color = palette[country];
      if (color) {
        var rect = g.querySelector('rect');
        if (rect) rect.setAttribute('fill', color);
      }
    });
    /* legend swatches */
    var countries = ['USA','China','UK','Germany','France','India'];
    svg.querySelectorAll('.lgd-bg ~ g rect, .lgd-bg + text ~ g rect').forEach(function(){});
    svg.querySelectorAll('[transform^="translate(886"]').forEach(function(g) {
      var txt = g.querySelector('text');
      if (!txt) return;
      var country = txt.textContent.trim();
      var color = palette[country];
      var rect = g.querySelector('rect');
      if (color && rect) rect.setAttribute('fill', color);
    });
  }

  function setMode(wantDark) {
    var currently = svg.classList.contains('dark');
    if (wantDark === currently) return;
    var thumb = document.getElementById('tthumb');
    var lbl   = document.getElementById('tlabel');
    if (wantDark) {
      svg.classList.add('dark');
      if (thumb) thumb.setAttribute('cx','52');
      if (lbl)   lbl.textContent = 'Light';
    } else {
      svg.classList.remove('dark');
      if (thumb) thumb.setAttribute('cx','16');
      if (lbl)   lbl.textContent = 'Dark';
    }
    swapCellColors(wantDark);
  }
  document.getElementById('dark-toggle').addEventListener('click', function() {
    setMode(!svg.classList.contains('dark'));
  });
  document.getElementById('print-toggle').addEventListener('click', function() {
    var thumb = document.getElementById('pthumb'), lbl = document.getElementById('plabel');
    if (svg.classList.toggle('print')) { thumb.setAttribute('cx','52'); lbl.textContent='Screen'; }
    else                               { thumb.setAttribute('cx','16'); lbl.textContent='Print'; }
  });
  window.setMode = setMode;
  window.addEventListener('message', function(e) {
    if (e.data && e.data.type === 'setMode') setMode(e.data.dark);
  });
  (function(){ setMode(window.location.href.indexOf('theme=dark')!==-1); })();
})();
